400 Constant *Constant::getIntegerValue(Type *Ty, const APInt &V) {
401   Type *ScalarTy = Ty->getScalarType();
402 
403   // Create the base integer constant.
404   Constant *C = ConstantInt::get(Ty->getContext(), V);
